cleaned = cleaned.replace(/^https?:\/\//, '');
cleaned = cleaned.replace(/^www\./, '');
cleaned = cleaned.replace(/\/$/, '');

const fullUrl = 'https://' + cleaned;

return [{
  json: {
    website: fullUrl,
    domain: cleaned
  }
}];

const tavilyData = $input.first().json;
