const response = $input.first().json;
const previousData = $('Parse Signals').item.json;

// Try Gemini format first, then Groq
let text = response?.candidates?.[0]?.content?.parts?.[0]?.text 
        || response?.choices?.[0]?.message?.content 
        || '';

if (!text) {
  throw new Error('Both Gemini and Groq returned no outreach text');
}

text = text.trim();
text = text.replace(/^```json\s*/i, '');
text = text.replace(/^```\s*/i, '');
text = text.replace(/```\s*$/i, '');
text = text.trim();

let outreach;
try {
  outreach = JSON.parse(text);
} catch (err) {
  throw new Error('Failed to parse outreach JSON: ' + err.message + '\n\nRaw: ' + text);
}

// Fix cold_email if it's a string
let coldEmail = outreach.cold_email;
if (typeof coldEmail === 'string') {
  coldEmail = {
    subject: "Quick question about your organic traffic",
    body: coldEmail
  };
}

return [{
  json: {
    ...previousData,
    outreach: {
      cold_email: coldEmail || {},
      linkedin_connection: outreach.linkedin_connection || '',
      linkedin_followup: outreach.linkedin_followup || '',
      call_opener: outreach.call_opener || '',
      voicemail_script: outreach.voicemail_script || ''
    }
  }
}];

const input = $input.first().json;
const previousData = {
  website: $('Clean URL').item.json.website,
  domain: $('Clean URL').item.json.domain
};

// Handle case where fetch failed (Continue on Fail)
let html = '';
try {
  html = input.data || input.body || '';
  if (typeof html !== 'string') {
    html = JSON.stringify(html);
  }
} catch (e) {
  html = '';
}

// If no HTML, return empty but continue
if (!html || html.length < 100) {
  return [{
    json: {
      ...previousData,
      website_text: '',
      website_available: false
    }
  }];
}

// Remove scripts, styles, and other noise
let cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
  .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
  .replace(/<!--[\s\S]*?-->/g, ' ');

// Extract meta tags (often has best description)
const titleMatch = cleaned.match(/<title[^>]*>([^<]*)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : '';

const descMatch = cleaned.match(/<meta\s+name=["']description["']\s+content=["']([^"']*)["']/i);
const metaDescription = descMatch ? descMatch[1].trim() : '';

const ogDescMatch = cleaned.match(/<meta\s+property=["']og:description["']\s+content=["']([^"']*)["']/i);
const ogDescription = ogDescMatch ? ogDescMatch[1].trim() : '';

// Remove all remaining HTML tags
cleaned = cleaned.replace(/<[^>]+>/g, ' ');

// Decode common HTML entities
cleaned = cleaned
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&apos;/g, "'");

// Collapse whitespace
cleaned = cleaned.replace(/\s+/g, ' ').trim();

// Limit to first 5000 chars (Gemini context management)
const truncated = cleaned.substring(0, 5000);

// Build summary
const websiteText = `TITLE: ${title}
META DESCRIPTION: ${metaDescription}
OG DESCRIPTION: ${ogDescription}

PAGE CONTENT:
${truncated}`;

return [{
  json: {
    ...previousData,
    website_text: websiteText,
    website_available: true,
    page_title: title,
    meta_description: metaDescription
  }
}];

